import type * as React from 'react';

export type Slot = React.ReactNode;

export const resolveSlot = (
  slot: Slot,
  options: {
    defaultNode: React.ReactNode;
  },
): React.ReactNode => {
  if (slot === null) {
    return null;
  }
  if (slot) {
    return slot;
  }
  return options.defaultNode;
};
